input.command:
RUN_ID="$ZEALT_RUN_ID" && \
curl -s -X POST "https://api.hookdeck.com/2025-07-01/connections" \
  -H "Authorization: Bearer $HOOKDECK_API_KEY" \
  -H "Content-Type: application/json" \
  -d "{
    \"source\": {
      \"name\": \"dedup-src-${RUN_ID}\",
      \"type\": \"WEBHOOK\"
    },
    \"destination\": {
      \"name\": \"dedup-dst-${RUN_ID}\",
      \"type\": \"MOCK_API\"
    },
    \"rules\": [
      {
        \"type\": \"deduplicate\",
        \"window\": 300000,
        \"include_fields\": [\"body.id\", \"body.type\"]
      }
    ]
  }" | jq .

